(()=>{'use strict';
const T=v=>String(v??'').trim();
const N=v=>Number(String(v??'').replace(/,/g,''))||0;
const $=s=>document.querySelector(s);
const coll=new Intl.Collator('th-u-kn-true',{numeric:true,sensitivity:'base'});
let rawPayload=null,rawRows=[],rawMeta={},overlay,body,draftExcluded=null;
function rowsOf(p){return p?.rows||p||[]}
function cleanPs(v){const parts=T(v).split(/\s+/).filter(Boolean);if(!parts.length)return'';if(parts.length===2&&parts[0]===parts[1])return parts[0];const out=[];parts.forEach(x=>{if(!out.includes(x))out.push(x)});return out.join(' ')}
function dateList(){return[...new Set((window.DOIT_SELECTED_DATES||[]).map(T).filter(Boolean))].sort()}
function psList(){return[...new Set((window.DOIT_SELECTED_PS_LIST||[]).map(cleanPs).filter(Boolean))].sort(coll.compare)}
function excluded(){return new Set((window.DOIT_EXCLUDED_ORDER_STORES||[]).map(T).filter(Boolean))}
function inBaseScope(r){const ds=dateList(),ps=psList();return(!ds.length||ds.includes(T(r.date)))&&(!ps.length||ps.includes(cleanPs(r.ps)))}
function stats(){const m=new Map();rawRows.filter(inBaseScope).forEach(r=>{const s=T(r.store)||'ไม่ระบุร้าน';let x=m.get(s);if(!x){x={store:s,rows:0,qty:0,bills:new Set()};m.set(s,x)}x.rows++;x.qty+=N(r.qty);if(T(r.inv))x.bills.add(T(r.inv))});return[...m.values()].sort((a,b)=>coll.compare(a.store,b.store))}
function label(){const all=stats().length,ex=excluded().size,use=Math.max(0,all-ex);return all?`กรองร้านออเดอร์: ใช้ ${use}/${all} ร้าน ▼`:'กรองร้านออเดอร์: ไม่มีข้อมูลร้าน ▼'}
function syncBtn(){const b=$('#orderStoreFilterBtn297');if(b)b.textContent=label()}
function css(){if($('#orderStoreFilterCss297'))return;const st=document.createElement('style');st.id='orderStoreFilterCss297';st.textContent='.orderStoreBtn297{height:34px;border:1px solid #2563eb;color:#1d4ed8;background:#eff6ff;border-radius:8px;font-weight:950;padding:0 10px}.orderStoreOverlay297{position:fixed;inset:0;background:rgba(15,23,42,.55);z-index:174;display:none;align-items:center;justify-content:center;padding:14px}.orderStoreOverlay297.on{display:flex}.orderStoreSheet297{width:min(94vw,760px);max-height:88vh;background:#fff;border-radius:18px;box-shadow:0 22px 80px #0006;display:flex;flex-direction:column;overflow:hidden}.orderStoreHead297{background:#1d4ed8;color:#fff;padding:14px 16px;display:flex;justify-content:space-between;align-items:center;gap:8px}.orderStoreClose297{height:34px;border:1px solid #ffffff66;background:#0001;color:#fff;border-radius:8px;font-weight:900;padding:0 12px}.orderStoreSearch297{padding:12px;border-bottom:1px solid #e5e7eb}.orderStoreSearch297 input{width:100%;height:44px;border:1px solid #cbd5e1;border-radius:10px;padding:0 12px;font-weight:900;font-size:15px}.orderStoreCount297{padding:8px 12px;border-bottom:1px solid #e5e7eb;background:#f8fafc;font-size:13px;font-weight:900;color:#374151}.orderStoreBody297{padding:12px;overflow:auto}.orderStoreGrid297{display:grid;grid-template-columns:repeat(2,1fr);gap:9px}.orderStoreItem297{border:1px solid #d1d5db;background:#fff;border-radius:10px;padding:10px;font-weight:950;text-align:left;font-size:14px;display:flex;gap:8px;align-items:flex-start}.orderStoreItem297 i{width:20px;height:20px;border:1px solid #9ca3af;border-radius:5px;display:inline-grid;place-items:center;font-style:normal;flex:0 0 auto}.orderStoreItem297.on{border-color:#16a34a;background:#ecfdf5;color:#065f27}.orderStoreItem297.on i{background:#16a34a;color:#fff;border-color:#16a34a}.orderStoreItem297.off{border-color:#ef4444;background:#fef2f2;color:#991b1b}.orderStoreItem297 small{display:block;color:#64748b;font-weight:800;margin-top:3px}.orderStoreFoot297{padding:12px;border-top:1px solid #e5e7eb;display:grid;grid-template-columns:1fr 1fr 1fr;gap:10px}.orderStoreFoot297 button{height:46px;border-radius:10px;font-weight:950;font-size:15px}.orderStoreClear297{border:1px solid #d1d5db;background:#fff;color:#4b5563}.orderStoreInvert297{border:1px solid #f59e0b;background:#fff7ed;color:#b45309}.orderStoreOk297{border:0;background:#1d4ed8;color:#fff}@media(max-width:720px){.orderStoreGrid297{grid-template-columns:1fr}.orderStoreSheet297{width:96vw;max-height:90vh}}';document.head.appendChild(st)}
function ensure(){css();if(overlay)return;overlay=document.createElement('div');overlay.className='orderStoreOverlay297';overlay.innerHTML='<div class="orderStoreSheet297"><div class="orderStoreHead297"><b>กรองร้านออเดอร์</b><button class="orderStoreClose297">ปิด</button></div><div class="orderStoreSearch297"><input id="orderStoreSearch297" placeholder="ค้นหาร้านออเดอร์"></div><div class="orderStoreCount297" id="orderStoreCount297">ใช้ทุกร้าน</div><div class="orderStoreBody297"></div><div class="orderStoreFoot297"><button class="orderStoreClear297">เลือกทั้งหมด</button><button class="orderStoreInvert297">สลับเลือก</button><button class="orderStoreOk297">ตกลง</button></div></div>';document.body.appendChild(overlay);body=overlay.querySelector('.orderStoreBody297');overlay.querySelector('.orderStoreClose297').onclick=cancel;overlay.querySelector('.orderStoreOk297').onclick=commit;overlay.querySelector('.orderStoreClear297').onclick=()=>{draftExcluded=new Set();render()};overlay.querySelector('.orderStoreInvert297').onclick=()=>{const all=stats().map(x=>x.store);const d=draft();draftExcluded=new Set(all.filter(x=>!d.has(x)));render()};overlay.onclick=e=>{if(e.target===overlay)cancel()};overlay.querySelector('#orderStoreSearch297').oninput=render}
function draft(){if(!draftExcluded)draftExcluded=new Set(excluded());return draftExcluded}
function render(){ensure();const q=T($('#orderStoreSearch297')?.value).toLowerCase(),d=draft();let list=stats();if(q)list=list.filter(x=>x.store.toLowerCase().includes(q));const all=stats().length,use=Math.max(0,all-d.size);const c=$('#orderStoreCount297');if(c)c.textContent=`ใช้ ${use}/${all} ร้าน · ติ๊กออก = ตัดออเดอร์ร้านนั้นออกจากรายการถอดของ`;body.innerHTML='<div class="orderStoreGrid297">'+list.map(x=>{const on=!d.has(x.store);return `<button class="orderStoreItem297 ${on?'on':'off'}" data-v="${x.store.replace(/"/g,'&quot;')}"><i>${on?'✓':''}</i><span>${x.store}<small>${x.rows.toLocaleString('th-TH')} รายการ · ${x.bills.size.toLocaleString('th-TH')} บิล · ${x.qty.toLocaleString('th-TH')} ชิ้น</small></span></button>`}).join('')+'</div>';body.querySelectorAll('.orderStoreItem297').forEach(btn=>btn.onclick=()=>{const v=btn.dataset.v;if(d.has(v))d.delete(v);else d.add(v);render()})}
function open(){ensure();draftExcluded=new Set(excluded());const s=$('#orderStoreSearch297');if(s)s.value='';render();overlay.classList.add('on')}
function cancel(){draftExcluded=null;overlay?.classList.remove('on');syncBtn()}
function commit(){const arr=[...draft()].sort(coll.compare);window.DOIT_EXCLUDED_ORDER_STORES=arr;draftExcluded=null;overlay?.classList.remove('on');syncBtn();document.dispatchEvent(new CustomEvent('doit:orderStoreFilterChanged',{detail:{excluded:arr}}))}
function install(){css();let host=document.querySelector('.summaryHead .actions')||document.querySelector('.actions')||document.querySelector('.tableTop');if(!host)return;if(!$('#orderStoreFilterBtn297')){const b=document.createElement('button');b.id='orderStoreFilterBtn297';b.type='button';b.className='orderStoreBtn297';b.onclick=open;host.prepend(b)}syncBtn()}
function patchLoad(){const app=window.DOIT_JSON_APP;if(!app||app.__orderStoreFilter297)return false;const old=app.load.bind(app);app.load=(payload,m={})=>{const arr=rowsOf(payload);if(Array.isArray(arr)&&arr.length>=rawRows.length){rawPayload=payload;rawMeta=m||{};rawRows=arr}const res=old(payload,m);setTimeout(install,100);setTimeout(syncBtn,200);return res};app.__orderStoreFilter297=true;return true}
function boot(){install();patchLoad();let n=0;const tick=()=>{install();patchLoad();if(++n<12)setTimeout(tick,500)};setTimeout(tick,300)}
document.addEventListener('DOMContentLoaded',boot);if(document.readyState!=='loading')boot();
})();